svg.script:
const SVG_NS = 'http://www.w3.org/2000/svg';
let initValue = 7.03;

//!export-start
let _pn_value = initValue;
let _pn_min = 0;
let _pn_max = 100;
let _pn_majorStep = 20;
let _pn_minorStep = 2;
let _pn_labelStep = 20;
let _pn_scaleFontSize = 11;
let _pn_startAngle = 135;
let _pn_endAngle = 405;
let _pn_animationDuration = 500;
let _pn_animationSteps = 24;
let _pb_showLabels = true;
let _pb_showTicks = true;
let _pb_showNeedleShadow = true;
let _pc_faceColor = '#ffffffff';
let _pc_ringColor = '#f3f3f3ff';
let _pc_scaleBandColor = '#b8b8b8ff';
let _pc_scaleColor = '#4f4f4fff';
let _pc_needleColor = '#ff7777ff';
let _pc_hubColor = '#eeeeeeff';
//!export-end

const cx = 110;
const cy = 96;
const outerRadius = 72;
const tickOuterRadius = 70;
const tickInnerMinorRadius = 64;
const tickInnerMajorRadius = 58;
const labelRadius = 48;

let currentDisplayValue = Number(initValue);
let animationTimer = null;
let animationToken = 0;

function el(id) {
  return document.getElementById(id);
}

function createSvgElement(name, attrs) {
  const node = document.createElementNS(SVG_NS, name);
  for (const key in attrs) {
    node.setAttribute(key, attrs[key]);
  }
  return node;
}

function clearNode(node) {
  while (node.firstChild) node.removeChild(node.firstChild);
}

function toBool(value) {
  return value === true || value === 'true' || value === 1 || value === '1';
}

function clamp(value, min, max) {
  const n = Number(value);
  if (!isFinite(n)) return min;
  return Math.max(min, Math.min(max, n));
}

function polarToCartesian(angleDeg, radius) {
  const angleRad = angleDeg * Math.PI / 180;
  return {
    x: cx + radius * Math.cos(angleRad),
    y: cy + radius * Math.sin(angleRad)
  };
}

function getAngle(value) {
  const min = Number(_pn_min);
  const max = Number(_pn_max);
  const start = Number(_pn_startAngle);
  const end = Number(_pn_endAngle);
  if (max === min) return start;
  const pct = (clamp(value, min, max) - min) / (max - min);
  return start + pct * (end - start);
}

function arcPath(radius, startAngle, endAngle) {
  const start = polarToCartesian(startAngle, radius);
  const end = polarToCartesian(endAngle, radius);
  const sweep = Math.abs(endAngle - startAngle);
  const largeArcFlag = sweep > 180 ? 1 : 0;
  const sweepFlag = endAngle > startAngle ? 1 : 0;
  return 'M ' + start.x + ' ' + start.y + ' A ' + radius + ' ' + radius + ' 0 ' + largeArcFlag + ' ' + sweepFlag + ' ' + end.x + ' ' + end.y;
}

function buildScale() {
  const ticksGroup = el('ticksGroup');
  const labelsGroup = el('labelsGroup');
  clearNode(ticksGroup);
  clearNode(labelsGroup);

  const min = Number(_pn_min);
  const max = Number(_pn_max);
  const majorStep = Math.max(1, Number(_pn_majorStep) || 20);
  const minorStep = Math.max(0.1, Number(_pn_minorStep) || 2);
  const labelStep = Math.max(1, Number(_pn_labelStep) || majorStep);
  const showTicks = toBool(_pb_showTicks);
  const showLabels = toBool(_pb_showLabels);

  el('scaleBand').setAttribute('d', arcPath(outerRadius, Number(_pn_startAngle), Number(_pn_endAngle)));
  el('scaleBandBorder').setAttribute('d', arcPath(outerRadius, Number(_pn_startAngle), Number(_pn_endAngle)));

  const first = Math.ceil(min / minorStep) * minorStep;
  for (let v = first; v <= max + 0.0001; v += minorStep) {
    const angle = getAngle(v);
    const isMajor = Math.abs((v / majorStep) - Math.round(v / majorStep)) < 0.0001;
    const isLabel = Math.abs((v / labelStep) - Math.round(v / labelStep)) < 0.0001;

    if (showTicks) {
      const p1 = polarToCartesian(angle, tickOuterRadius);
      const p2 = polarToCartesian(angle, isMajor ? tickInnerMajorRadius : tickInnerMinorRadius);
      ticksGroup.appendChild(createSvgElement('line', {
        x1: p1.x,
        y1: p1.y,
        x2: p2.x,
        y2: p2.y,
        stroke: _pc_scaleColor,
        'stroke-width': isMajor ? 2.2 : 1.2,
        'stroke-linecap': 'butt'
      }));
    }

    if (showLabels && isLabel) {
      const lp = polarToCartesian(angle, labelRadius);
      const label = createSvgElement('text', {
        x: lp.x,
        y: lp.y + 4,
        'text-anchor': 'middle',
        'font-family': 'Arial, sans-serif',
        'font-size': _pn_scaleFontSize,
        'font-weight': 'bold',
        fill: _pc_scaleColor
      });
      label.textContent = Math.round(v);
      labelsGroup.appendChild(label);
    }
  }
}

function applyStyle() {
  el('innerFace').style.fill = _pc_faceColor;
  el('outerRing').style.fill = _pc_ringColor;
  el('scaleBand').style.stroke = _pc_scaleBandColor;
  el('scaleBandBorder').style.stroke = _pc_scaleColor;
  el('needle').style.stroke = _pc_needleColor;
  el('hub').style.fill = _pc_hubColor;
  el('needleShadow').style.display = toBool(_pb_showNeedleShadow) ? 'inline' : 'none';
  buildScale();
}

function applyDisplayValue(value) {
  currentDisplayValue = Number(value);
  const angle = getAngle(currentDisplayValue);
  const tip = polarToCartesian(angle, 64);
  const tail = polarToCartesian(angle + 180, 10);
  const needlePath = 'M ' + tail.x + ' ' + tail.y + ' L ' + tip.x + ' ' + tip.y;
  el('needle').setAttribute('d', needlePath);
  el('needleShadow').setAttribute('d', needlePath);
}

function easeInOut(t) {
  return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
}

function stopAnimation() {
  animationToken += 1;
  if (animationTimer) {
    clearInterval(animationTimer);
    animationTimer = null;
  }
}

function updateValue(value, animate) {
  const targetValue = Number(value);
  _pn_value = isFinite(targetValue) ? targetValue : Number(_pn_min);

  const duration = Math.max(0, Number(_pn_animationDuration) || 0);
  const steps = Math.max(1, Math.min(80, Math.round(Number(_pn_animationSteps) || 24)));

  if (animate === false || duration <= 0) {
    stopAnimation();
    applyDisplayValue(_pn_value);
    return;
  }

  stopAnimation();
  const token = animationToken;
  const startValue = Number(currentDisplayValue);
  const delta = _pn_value - startValue;
  let step = 0;
  const interval = Math.max(10, duration / steps);

  animationTimer = setInterval(function () {
    if (token !== animationToken) {
      clearInterval(animationTimer);
      animationTimer = null;
      return;
    }

    step += 1;
    const t = Math.min(1, step / steps);
    applyDisplayValue(startValue + delta * easeInOut(t));

    if (t >= 1) {
      clearInterval(animationTimer);
      animationTimer = null;
      applyDisplayValue(_pn_value);
    }
  }, interval);
}

function init() {
  applyStyle();
  updateValue(_pn_value, false);
}

function putValue(id, value) {
  if (id === '_pn_value') {
    updateValue(value);
    return;
  }

  if (id === '_pn_min') _pn_min = Number(value);
  if (id === '_pn_max') _pn_max = Number(value);
  if (id === '_pn_majorStep') _pn_majorStep = Number(value);
  if (id === '_pn_minorStep') _pn_minorStep = Number(value);
  if (id === '_pn_labelStep') _pn_labelStep = Number(value);
  if (id === '_pn_scaleFontSize') _pn_scaleFontSize = Number(value);
  if (id === '_pn_startAngle') _pn_startAngle = Number(value);
  if (id === '_pn_endAngle') _pn_endAngle = Number(value);
  if (id === '_pn_animationDuration') _pn_animationDuration = Number(value);
  if (id === '_pn_animationSteps') _pn_animationSteps = Number(value);
  if (id === '_pb_showLabels') _pb_showLabels = toBool(value);
  if (id === '_pb_showTicks') _pb_showTicks = toBool(value);
  if (id === '_pb_showNeedleShadow') _pb_showNeedleShadow = toBool(value);
  if (id === '_pc_faceColor') _pc_faceColor = value;
  if (id === '_pc_ringColor') _pc_ringColor = value;
  if (id === '_pc_scaleBandColor') _pc_scaleBandColor = value;
  if (id === '_pc_scaleColor') _pc_scaleColor = value;
  if (id === '_pc_needleColor') _pc_needleColor = value;
  if (id === '_pc_hubColor') _pc_hubColor = value;

  applyStyle();
  updateValue(_pn_value, false);
}

init();
